import { useCallback, useEffect, useRef, useState } from "react";

import { getSetting, setSetting } from "../db/repositories/settingsRepo";
import { prepareForTts } from "./ttsText";
import type { TtsVoice } from "./ttsBackend";
import { TtsManager } from "./ttsManager";
import { WebSpeechTts } from "./webSpeechTts";
import { EdgeTts } from "./edgeTts";

const TTS_AUTO_KEY = "tts_auto";
const TTS_SPEED_KEY = "tts_speed";
const TTS_VOICE_KEY = "tts_voice";
const TTS_PITCH_KEY = "tts_pitch";
const TTS_BACKEND_KEY = "tts_backend";

const DEFAULT_SPEED = 1.0;
const DEFAULT_PITCH = 0; // Hz offset

// ---------------------------------------------------------------------------
// Singleton TTS manager — created once per app lifetime
// ---------------------------------------------------------------------------
let managerInstance: TtsManager | null = null;

function getManager(): TtsManager {
  if (!managerInstance) {
    managerInstance = new TtsManager(new WebSpeechTts(), new EdgeTts());
  }
  return managerInstance;
}

// ---------------------------------------------------------------------------
// Hook interface — extended with backend, pitch, and combined voice list
// ---------------------------------------------------------------------------
export interface TtsHook {
  /** Speak the given text after stripping markdown. */
  speak: (text: string, voiceUri?: string) => void;
  /** Stop current speech immediately. */
  stop: () => void;
  /** Whether speech is currently playing. */
  isSpeaking: boolean;
  /** Available voices from all backends (populated asynchronously). */
  voices: TtsVoice[];
  /** Enable/disable auto-read mode (persisted). */
  autoRead: boolean;
  setAutoRead: (v: boolean) => void;
  /** Speech rate multiplier (0.5–2.0, persisted). */
  speed: number;
  setSpeed: (v: number) => void;
  /** Currently selected global voice ID (persisted). */
  selectedVoiceUri: string;
  setSelectedVoiceUri: (v: string) => void;
  /** Active backend index (0 = edge-tts, 1 = web-speech, persisted). */
  backend: number;
  setBackend: (v: number) => void;
  /** Pitch offset in Hz (-20..+20, persisted). */
  pitch: number;
  setPitch: (v: number) => void;
}

// ---------------------------------------------------------------------------
export function useTts(): TtsHook {
  const manager = getManager();
  const [autoRead, setAutoReadState] = useState(false);
  const [speed, setSpeedState] = useState(DEFAULT_SPEED);
  const [pitch, setPitchState] = useState(DEFAULT_PITCH);
  const [selectedVoiceUri, setSelectedVoiceUriState] = useState("");
  const [backend, setBackendState] = useState(0);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [voices, setVoices] = useState<TtsVoice[]>([]);
  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);

  // Load persisted settings on mount
  useEffect(() => {
    void (async () => {
      const [auto, spd, voice, ptch, bknd] = await Promise.all([
        getSetting(TTS_AUTO_KEY),
        getSetting(TTS_SPEED_KEY),
        getSetting(TTS_VOICE_KEY),
        getSetting(TTS_PITCH_KEY),
        getSetting(TTS_BACKEND_KEY),
      ]);
      if (auto) setAutoReadState(auto === "1");
      if (spd) setSpeedState(Number(spd) || DEFAULT_SPEED);
      if (voice) setSelectedVoiceUriState(voice);
      if (ptch) setPitchState(Number(ptch) || DEFAULT_PITCH);
      if (bknd) setBackendState(Number(bknd) || 0);
    })();
  }, []);

  // Sync backend preference to manager
  useEffect(() => {
    manager.setPreferredIndex(backend);
  }, [backend, manager]);

  // Populate available voices from all backends
  useEffect(() => {
    let cancelled = false;
    void (async () => {
      const list = await manager.listVoices();
      if (!cancelled) setVoices(list);
    })();
    return () => {
      cancelled = true;
    };
  }, [backend, manager]);

  // Poll isSpeaking (event-driven doesn't cover all backends)
  useEffect(() => {
    pollRef.current = setInterval(() => {
      setIsSpeaking(manager.isSpeaking);
    }, 200);
    return () => {
      if (pollRef.current) clearInterval(pollRef.current);
    };
  }, [manager]);

  const stop = useCallback(() => {
    manager.stop();
    setIsSpeaking(false);
  }, [manager]);

  const speak = useCallback(
    (text: string, voiceUri?: string) => {
      const cleaned = prepareForTts(text);
      if (!cleaned) return;

      manager.stop();

      const targetVoice = voiceUri || selectedVoiceUri;

      void manager.speak(cleaned, {
        voice: targetVoice || undefined,
        rate: speed,
        pitch,
      });
    },
    [manager, speed, pitch, selectedVoiceUri],
  );

  const setAutoRead = useCallback((v: boolean) => {
    setAutoReadState(v);
    void setSetting(TTS_AUTO_KEY, v ? "1" : "0");
  }, []);

  const setSpeed = useCallback((v: number) => {
    const clamped = Math.max(0.5, Math.min(2.0, v));
    setSpeedState(clamped);
    void setSetting(TTS_SPEED_KEY, String(clamped));
  }, []);

  const setPitch = useCallback((v: number) => {
    const clamped = Math.max(-20, Math.min(20, v));
    setPitchState(clamped);
    void setSetting(TTS_PITCH_KEY, String(clamped));
  }, []);

  const setSelectedVoiceUri = useCallback((v: string) => {
    setSelectedVoiceUriState(v);
    void setSetting(TTS_VOICE_KEY, v);
  }, []);

  const setBackend = useCallback((v: number) => {
    const clamped = Math.max(0, Math.min(1, v));
    setBackendState(clamped);
    void setSetting(TTS_BACKEND_KEY, String(clamped));
  }, []);

  return {
    speak,
    stop,
    isSpeaking,
    voices,
    autoRead,
    setAutoRead,
    speed,
    setSpeed,
    selectedVoiceUri,
    setSelectedVoiceUri,
    backend,
    setBackend,
    pitch,
    setPitch,
  };
}

import type { TtsBackend, TtsSpeakOptions, TtsVoice } from "./ttsBackend";
import type { WebSpeechTts } from "./webSpeechTts";
import type { EdgeTts } from "./edgeTts";

export class TtsManager implements TtsBackend {
  readonly id = "edge-tts" as const; // primary backend ID
  readonly label = "Auto (Edge-TTS → Web Speech)";

  private backends: TtsBackend[];


  constructor(webSpeech: WebSpeechTts, edgeTts: EdgeTts) {
    // Edge-TTS first (online, better quality), Web Speech as fallback
    this.backends = [edgeTts, webSpeech];
  }

  /**
   * Try each backend in order. The first one that succeeds wins.
   * On failure, log the error and continue to the next backend.
   */
  async speak(text: string, options?: TtsSpeakOptions): Promise<void> {
    for (let i = 0; i < this.backends.length; i++) {
      try {
        await this.backends[i].speak(text, options);
        return;
      } catch (e) {
        console.warn(`TTS backend "${this.backends[i].id}" failed:`, e);
        // Continue to next backend
      }
    }
    // All backends failed — nothing we can do
    console.error("All TTS backends failed");
  }

  stop(): void {
    this.backends.forEach((b) => b.stop());
  }

  get isSpeaking(): boolean {
    return this.backends.some((b) => b.isSpeaking);
  }

  async listVoices(): Promise<TtsVoice[]> {
    // Merge voices from all backends, Edge-TTS first
    const results: TtsVoice[] = [];
    const seen = new Set<string>();

    for (const backend of this.backends) {
      try {
        const voices = await backend.listVoices();
        for (const v of voices) {
          if (!seen.has(v.id)) {
            seen.add(v.id);
            results.push(v);
          }
        }
      } catch {
        // Skip backends that fail to list voices
      }
    }
    return results;
  }

  /** Set which backend to prefer (0 = edge-tts, 1 = web-speech). */
  setPreferredIndex(index: number): void {
    if (index >= 0 && index < this.backends.length) {
      // preference stored for future fallback logic
    }
  }

  /** The backends array — for UI introspection. */
  getBackends(): ReadonlyArray<TtsBackend> {
    return this.backends;
  }
}

import type { TtsBackend, TtsSpeakOptions, TtsVoice } from "./ttsBackend";
import { prepareForTts } from "./ttsText";

export class WebSpeechTts implements TtsBackend {
  readonly id = "web-speech" as const;
  readonly label = "Web Speech";

  private synth: SpeechSynthesis | null;
  private _isSpeaking = false;

  constructor() {
    this.synth = typeof window !== "undefined" ? window.speechSynthesis : null;
  }

  get isSpeaking(): boolean {
    if (this.synth) {
      return this.synth.speaking;
    }
    return this._isSpeaking;
  }

  async speak(text: string, options?: TtsSpeakOptions): Promise<void> {
    const synth = this.synth;
    if (!synth) return;

    // Stop any current speech
    synth.cancel();

    const cleaned = prepareForTts(text);
    if (!cleaned) return;

    const utterance = new SpeechSynthesisUtterance(cleaned);

    // Apply rate
    if (options?.rate !== undefined) {
      utterance.rate = Math.max(0.5, Math.min(2.0, options.rate));
    }

    // Apply pitch
    if (options?.pitch !== undefined) {
      // Web Speech pitch is 0..2, default 1.0
      // Map Hz offset (-20..+20) to pitch range (0.5..1.5)
      const normalized = Math.max(-20, Math.min(20, options.pitch));
      utterance.pitch = 1.0 + (normalized / 20) * 0.5;
    }

    // Select voice by URI/name
    if (options?.voice) {
      const allVoices = synth.getVoices();
      const match =
        allVoices.find((v) => v.voiceURI === options.voice) ||
        allVoices.find((v) => v.name === options.voice) ||
        allVoices.find((v) => v.lang.startsWith(options.voice!));
      if (match) utterance.voice = match;
    }

    return new Promise<void>((resolve) => {
      utterance.onstart = () => {
        this._isSpeaking = true;
      };
      utterance.onend = () => {
        this._isSpeaking = false;
        resolve();
      };
      utterance.onerror = () => {
        this._isSpeaking = false;
        resolve();
      };

      synth.speak(utterance);
    });
  }

  stop(): void {
    if (this.synth) {
      this.synth.cancel();
    }
    this._isSpeaking = false;
  }

  async listVoices(): Promise<TtsVoice[]> {
    const synth = this.synth;
    if (!synth) return [];

    // Chrome/WebView loads voices asynchronously
    const getVoices = (): SpeechSynthesisVoice[] => {
      const voices = synth.getVoices();
      if (voices.length > 0) return voices;
      return [];
    };

    // Try immediate, then wait for voiceschanged
    const immediate = getVoices();
    if (immediate.length > 0) {
      return immediate.map((v) => ({
        id: v.voiceURI,
        name: v.name,
        lang: v.lang,
        backend: "web-speech" as const,
      }));
    }

    // Wait for voices to load
    return new Promise<TtsVoice[]>((resolve) => {
      const timeout = setTimeout(() => {
        synth.removeEventListener("voiceschanged", handler);
        resolve([]);
      }, 2000);

      const handler = () => {
        clearTimeout(timeout);
        synth.removeEventListener("voiceschanged", handler);
        resolve(
          getVoices().map((v) => ({
            id: v.voiceURI,
            name: v.name,
            lang: v.lang,
            backend: "web-speech" as const,
          })),
        );
      };

      synth.addEventListener("voiceschanged", handler);
    });
  }
}

export interface TtsVoice {
  id: string;       // e.g. "cs-CZ-AntoninNeural" or SpeechSynthesisVoice.voiceURI
  name: string;     // e.g. "Antonin" or "Google čeština"
  lang: string;     // e.g. "cs-CZ"
  backend: "web-speech" | "edge-tts";
}

export interface TtsSpeakOptions {
  voice?: string;
  pitch?: number;   // Hz offset, e.g. -15
  rate?: number;    // multiplier, e.g. 0.9
}

export interface TtsBackend {
  readonly id: "web-speech" | "edge-tts";
  readonly label: string;
  speak(text: string, options?: TtsSpeakOptions): Promise<void>;
  stop(): void;
  readonly isSpeaking: boolean;
  listVoices(): Promise<TtsVoice[]>;
}

