import { describe, expect, it } from "vitest";

import cs from "./cs.json";
import en from "./en.json";

/** Recursively collects every leaf key path (e.g. "chat.room.errors.generic")
 * from a nested translation object, so we can diff the two locale files
 * structurally rather than just checking top-level namespaces. */
function collectKeyPaths(obj: unknown, prefix = ""): string[] {
  if (obj === null || typeof obj !== "object") return [prefix];
  const entries = Object.entries(obj as Record<string, unknown>);
  return entries.flatMap(([key, value]) => collectKeyPaths(value, prefix ? `${prefix}.${key}` : key));
}

describe("i18n key parity", () => {
  it("cs.json and en.json declare exactly the same set of keys", () => {
    const csKeys = collectKeyPaths(cs).sort();
    const enKeys = collectKeyPaths(en).sort();

    const missingInEn = csKeys.filter((k) => !enKeys.includes(k));
    const missingInCs = enKeys.filter((k) => !csKeys.includes(k));

    expect(missingInEn, `keys present in cs.json but missing in en.json: ${missingInEn.join(", ")}`).toEqual([]);
    expect(missingInCs, `keys present in en.json but missing in cs.json: ${missingInCs.join(", ")}`).toEqual([]);
  });

  it("no translation value is an empty string", () => {
    const checkEmpty = (obj: unknown, prefix: string, file: string) => {
      if (obj === null || typeof obj !== "object") {
        expect(obj, `${file}: ${prefix} is empty`).not.toBe("");
        return;
      }
      for (const [key, value] of Object.entries(obj as Record<string, unknown>)) {
        checkEmpty(value, prefix ? `${prefix}.${key}` : key, file);
      }
    };
    checkEmpty(cs, "", "cs.json");
    checkEmpty(en, "", "en.json");
  });
});

import type { TtsBackend, TtsSpeakOptions, TtsVoice } from "./ttsBackend";
import { prepareForTts } from "./ttsText";

export class WebSpeechTts implements TtsBackend {
  readonly id = "web-speech" as const;
  readonly label = "Web Speech";

  private synth: SpeechSynthesis | null;
  private _isSpeaking = false;

  constructor() {
    this.synth = typeof window !== "undefined" ? window.speechSynthesis : null;
  }

  get isSpeaking(): boolean {
    if (this.synth) {
      return this.synth.speaking;
    }
    return this._isSpeaking;
  }

  async speak(text: string, options?: TtsSpeakOptions): Promise<void> {
    const synth = this.synth;
    if (!synth) {
      console.warn("[WebSpeechTts] window.speechSynthesis not available — TTS cannot work");
      throw new Error("Web Speech API not available (window.speechSynthesis is null)");
    }

    // Stop any current speech
    synth.cancel();

    const cleaned = prepareForTts(text);
    if (!cleaned) {
      console.warn("[WebSpeechTts] Text empty after cleaning, nothing to speak");
      throw new Error("Text empty after TTS preparation");
    }

    console.log("[WebSpeechTts] Speaking:", cleaned.slice(0, 60) + (cleaned.length > 60 ? "…" : ""));

    const utterance = new SpeechSynthesisUtterance(cleaned);

    // Apply rate
    if (options?.rate !== undefined) {
      utterance.rate = Math.max(0.5, Math.min(2.0, options.rate));
    }

    // Apply pitch
    if (options?.pitch !== undefined) {
      // Web Speech pitch is 0..2, default 1.0
      // Map Hz offset (-20..+20) to pitch range (0.5..1.5)
      const normalized = Math.max(-20, Math.min(20, options.pitch));
      utterance.pitch = 1.0 + (normalized / 20) * 0.5;
    }

    // Select voice by URI/name
    if (options?.voice) {
      const allVoices = synth.getVoices();
      const match =
        allVoices.find((v) => v.voiceURI === options.voice) ||
        allVoices.find((v) => v.name === options.voice) ||
        allVoices.find((v) => v.lang.startsWith(options.voice!));
      if (match) utterance.voice = match;
    }

    const SAFETY_TIMEOUT_MS = 30_000;

    return new Promise<void>((resolve, reject) => {
      let settled = false;

      const safetyTimer = setTimeout(() => {
        if (!settled) {
          settled = true;
          this._isSpeaking = false;
          synth.cancel();
          console.warn("[WebSpeechTts] Timed out after " + SAFETY_TIMEOUT_MS + " ms — no onend/onerror fired");
          reject(new Error("Web Speech timed out"));
        }
      }, SAFETY_TIMEOUT_MS);

      utterance.onstart = () => {
        this._isSpeaking = true;
        console.log("[WebSpeechTts] Utterance started");
      };
      utterance.onend = () => {
        if (settled) return;
        settled = true;
        clearTimeout(safetyTimer);
        this._isSpeaking = false;
        console.log("[WebSpeechTts] Utterance ended");
        resolve();
      };
      utterance.onerror = (event) => {
        if (settled) return;
        settled = true;
        clearTimeout(safetyTimer);
        this._isSpeaking = false;
        console.warn("[WebSpeechTts] Utterance error:", event.error);
        reject(new Error("Web Speech error: " + (event.error || "unknown")));
      };

      synth.speak(utterance);
    });
  }

  stop(): void {
    if (this.synth) {
      this.synth.cancel();
    }
    this._isSpeaking = false;
  }

  async listVoices(): Promise<TtsVoice[]> {
    const synth = this.synth;
    if (!synth) return [];

    // Chrome/WebView loads voices asynchronously
    const getVoices = (): SpeechSynthesisVoice[] => {
      const voices = synth.getVoices();
      if (voices.length > 0) return voices;
      return [];
    };

    // Try immediate, then wait for voiceschanged
    const immediate = getVoices();
    if (immediate.length > 0) {
      return immediate.map((v) => ({
        id: v.voiceURI,
        name: v.name,
        lang: v.lang,
        backend: "web-speech" as const,
      }));
    }

    // Wait for voices to load
    return new Promise<TtsVoice[]>((resolve) => {
      const timeout = setTimeout(() => {
        synth.removeEventListener("voiceschanged", handler);
        resolve([]);
      }, 2000);

      const handler = () => {
        clearTimeout(timeout);
        synth.removeEventListener("voiceschanged", handler);
        resolve(
          getVoices().map((v) => ({
            id: v.voiceURI,
            name: v.name,
            lang: v.lang,
            backend: "web-speech" as const,
          })),
        );
      };

      synth.addEventListener("voiceschanged", handler);
    });
  }
}

import type { TtsBackend, TtsSpeakOptions, TtsVoice } from "./ttsBackend";
import type { WebSpeechTts } from "./webSpeechTts";
import type { EdgeTts } from "./edgeTts";

export class TtsManager implements TtsBackend {
  readonly id = "edge-tts" as const; // primary backend ID
  readonly label = "Auto (Edge-TTS → Web Speech)";

  private backends: TtsBackend[];


  constructor(webSpeech: WebSpeechTts, edgeTts: EdgeTts) {
    // Edge-TTS first (online, better quality), Web Speech as fallback
    this.backends = [edgeTts, webSpeech];
  }

  /**
   * Try each backend in order. The first one that succeeds wins.
   * On failure, log the error and continue to the next backend.
   */
  async speak(text: string, options?: TtsSpeakOptions): Promise<void> {
    console.log("[TtsManager] speak() — trying backends in order:", this.backends.map((b) => b.id).join(", "));
    for (let i = 0; i < this.backends.length; i++) {
      try {
        console.log("[TtsManager] Trying backend:", this.backends[i].id);
        await this.backends[i].speak(text, options);
        console.log("[TtsManager] Backend succeeded:", this.backends[i].id);
        return;
      } catch (e) {
        console.warn(`[TtsManager] Backend "${this.backends[i].id}" failed:`, e);
        // Continue to next backend
      }
    }
    // All backends failed — nothing we can do
    console.error("[TtsManager] All TTS backends failed");
  }

  stop(): void {
    this.backends.forEach((b) => b.stop());
  }

  get isSpeaking(): boolean {
    return this.backends.some((b) => b.isSpeaking);
  }

  async listVoices(): Promise<TtsVoice[]> {
    // Merge voices from all backends, Edge-TTS first
    const results: TtsVoice[] = [];
    const seen = new Set<string>();

    for (const backend of this.backends) {
      try {
        const voices = await backend.listVoices();
        for (const v of voices) {
          if (!seen.has(v.id)) {
            seen.add(v.id);
            results.push(v);
          }
        }
      } catch {
        // Skip backends that fail to list voices
      }
    }
    return results;
  }

  /** Set which backend to prefer (0 = edge-tts, 1 = web-speech). */
  setPreferredIndex(index: number): void {
    if (index >= 0 && index < this.backends.length) {
      // preference stored for future fallback logic
    }
  }

  /** The backends array — for UI introspection. */
  getBackends(): ReadonlyArray<TtsBackend> {
    return this.backends;
  }

  /**
   * Health check: try speaking a short test phrase and report which backend
   * succeeded. Returns null if all backends failed.
   */
  async testSpeak(phrase: string): Promise<{ backend: string; label: string } | null> {
    for (const backend of this.backends) {
      try {
        await backend.speak(phrase);
        return { backend: backend.id, label: backend.label };
      } catch {
        // continue
      }
    }
    return null;
  }
}

